import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        Map<Long, List<Long>> pos = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            long num = nums[i];
            pos.putIfAbsent(num, new ArrayList<>());
            pos.get(num).add((long) i);
        }

        List<Long> uniqueElements = new ArrayList<>(pos.keySet());
        int q = queries.length;
        long[] ans = new long[q];
        for (int queryIdx = 0; queryIdx < q; queryIdx++) {
            long l = queries[queryIdx][0];
            long r = queries[queryIdx][1];
            long threshold = queries[queryIdx][2];
            long maxFreq = -1;
            long bestNum = -1;
            for (Long num : uniqueElements) {
                List<Long> indices = pos.get(num);
                int left = Collections.binarySearch(indices, l);
                if (left < 0) {
                    left = -left - 1;
                }
                int right = Collections.binarySearch(indices, r + 1);
                if (right < 0) {
                    right = -right - 1;
                }
                int count = right - left;
                if (count >= threshold) {
                    if (count > maxFreq || (count == maxFreq && num < bestNum)) {
                        maxFreq = count;
                        bestNum = num;
                    }
                }
            }
            ans[queryIdx] = (maxFreq >= threshold) ? bestNum : -1;
        }
        return ans;
    }
}
