import java.util.Map;
import java.util.HashMap;
import java.util.List;
import java.util.ArrayList;
import java.util.Collections;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        Map<Long, List<Long>> pos = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            long num = nums[i];
            pos.computeIfAbsent(num, k -> new ArrayList<>()).add((long) i);
        }

        int n = nums.length;
        int q = queries.length;
        long[] ans = new long[q];

        for (int queryIdx = 0; queryIdx < q; queryIdx++) {
            long l = queries[queryIdx][0];
            long r = queries[queryIdx][1];
            long threshold = queries[queryIdx][2];

            long max_freq = -1;
            long best_num = -1;

            for (Map.Entry<Long, List<Long>> entry : pos.entrySet()) {
                long num = entry.getKey();
                List<Long> indices = entry.getValue();

                int left = Collections.binarySearch(indices, l);
                if (left < 0) {
                    left = -left - 1;
                }

                int upper = Collections.binarySearch(indices, r + 1);
                if (upper < 0) {
                    upper = -upper - 1;
                }

                int count = upper - left;

                if (count >= threshold) {
                    if (count > max_freq || (count == max_freq && num < best_num)) {
                        max_freq = count;
                        best_num = num;
                    }
                }
            }

            ans[queryIdx] = (max_freq >= threshold) ? best_num : -1;
        }

        return ans;
    }
}
